INSERT INTO public.products (id, name, slug, brand_id, category_id, short_description, description, specifications, usability, tips, image_url, gallery_images, rating, review_count, is_featured, is_new, tags, created_at, status, publish_at, published_at, parent_product_id, variant_label) VALUES ('29d75a27-24c7-46fc-b9d6-d39ac9b48ee0', 'ALUMINA CUTMAX 1200 Composto Polidor Corte Pesado EasyTech 500ml', 'alumina-cutmax-1200-easytech-500ml', '16ed7769-be17-4581-8fbd-90a4d5d6499b', 'f13b7270-b3c6-449b-b1d0-78394cafbd51', 'Composto polidor de corte pesado. Remoção rápida de riscos e nivelamento de texturas.', 'O composto polidor de corte Alumina Cutmax é revolucionário, um verdadeiro produto One Step. Tremendo poder de corte e acabamento impecável. A capacidade de remoção rápida de riscos e nivelamento de texturas impressiona. É o primeiro composto de corte produzido para qualquer tipo de verniz, dos mais macios aos mais duros e complexos. Usa o exclusivo sistema EASY SIA de abrasivos inteligentes, formados em 5 tipos de grão. Sem geração de pó. Alternativa rápida e de extrema qualidade para processos de polimento.', '{"Tipo": "Composto Polidor", "Corte": "Pesado", "Marca": "EasyTech", "Volume": "500ml"}'::jsonb, '1. Alumina Cutmax pode ser usado em máquinas rotativas e roto orbitais. 2. Coloque produto na boina de polimento e espalhe com a máquina desligada. 3. Com o produto espalhado na peça, inicie o processo de polimento. 4. Na fase inicial trabalhe com uma leve pressão e mais velocidade. 5. Diminua a pressão e a velocidade a medida que os abrasivos forem quebrando. 6. Remova da peça com um pano de microfibras e use IPA ETS para inspeção final.', NULL, 'https://images.tcdn.com.br/img/img_prod/1152560/alumina_cutmax_1200_composto_polidor_de_corte_pesado_easytech_500ml_1951_1_166a2c6fc1095e45ac456d309fe7530a.jpg', '{}'::text[], 4.5, 2, false, true, '{}'::text[], '2026-07-12T00:06:02.620504+00:00', 'published', NULL, '2026-07-12T01:40:33.911531+00:00', NULL, NULL);
INSERT INTO public.products (id, name, slug, brand_id, category_id, short_description, description, specifications, usability, tips, image_url, gallery_images, rating, review_count, is_featured, is_new, tags, created_at, status, publish_at, published_at, parent_product_id, variant_label) VALUES ('6062980f-c286-462d-8dbb-5681fb8ee3ca', 'ALUMINA DETAILING 2500 Composto Polidor de Refino EasyTech 500ml', 'alumina-detailing-2500-easytech-500ml', '16ed7769-be17-4581-8fbd-90a4d5d6499b', 'f13b7270-b3c6-449b-b1d0-78394cafbd51', 'Composto polidor de refino. Nivelamento de texturas e preparo para lustro.', 'Sabemos que a cera de carnaúba é conhecida pelo brilho quente que proporciona à pintura. Com a evolução do mercado há crescente tendência para os produtos à base de polímeros e resinas sintéticas. A Easytech desenvolveu a Alumina Detailing, um composto de refino que alia o melhor dos dois mundos. A capacidade de refino e nivelamento de texturas impressiona, é o primeiro composto de refino produzido para qualquer tipo de verniz.', '{"Tipo": "Composto Polidor", "Corte": "Refino", "Marca": "EasyTech", "Volume": "500ml"}'::jsonb, 'Alumina Detailing pode ser usado em máquinas rotativas e roto orbitais. Coloque produto na boina de polimento e espalhe com a máquina desligada. Com o produto espalhado na peça, inicie o processo de polimento.', NULL, 'https://images.tcdn.com.br/img/img_prod/1152560/alumina_detailing_2500_composto_polidor_de_refino_easytech_500ml_1947_1_3248b76d3eb704a5b242a661a11fa72f.jpg', '{}'::text[], 4, 1, false, true, '{}'::text[], '2026-07-12T00:06:02.620504+00:00', 'published', NULL, '2026-07-12T01:40:33.911531+00:00', NULL, NULL);
INSERT INTO public.products (id, name, slug, brand_id, category_id, short_description, description, specifications, usability, tips, image_url, gallery_images, rating, review_count, is_featured, is_new, tags, created_at, status, publish_at, published_at, parent_product_id, variant_label) VALUES ('0e6cd462-5bae-4cd1-8eda-2a389991cc70', 'ALUMINA PERFECT GLOSS 3500 Composto Polidor de Lustro EasyTech 500ml', 'alumina-perfect-gloss-3500-easytech-500ml', '16ed7769-be17-4581-8fbd-90a4d5d6499b', 'f13b7270-b3c6-449b-b1d0-78394cafbd51', 'Composto polidor de lustro. Acabamento impecável e brilho intenso.', 'A capacidade de refino e nivelamento de texturas impressiona. É o primeiro composto de lustro produzido para qualquer tipo de verniz. Indicado para finalização de processos de polimento.', '{"Tipo": "Composto Polidor", "Corte": "Lustro", "Marca": "EasyTech", "Volume": "500ml"}'::jsonb, 'Alumina Perfect Gloss pode ser usado em máquinas rotativas e roto orbitais. Coloque produto na boina de polimento e espalhe com a máquina desligada. Com o produto espalhado na peça, inicie o processo de polimento.', NULL, 'https://images.tcdn.com.br/img/img_prod/1152560/alumina_perfect_gloss_3500_composto_polidor_de_lustro_easytech_500ml_1943_1_252c82346ee4c9ba147750c0a73875a7.jpg', '{}'::text[], 4.5, 1, false, true, '{}'::text[], '2026-07-12T00:06:02.620504+00:00', 'published', NULL, '2026-07-12T01:40:33.911531+00:00', NULL, NULL);
