INSERT INTO public.products (id, name, slug, brand_id, category_id, short_description, description, specifications, usability, tips, image_url, gallery_images, rating, review_count, is_featured, is_new, tags, created_at, status, publish_at, published_at, parent_product_id, variant_label) VALUES ('47f2a4af-d2f5-42e5-834f-2c2657973ea0', 'Areon Car Perfume Gold 50ml', 'areon-car-perfume-gold-50ml', '385f81e4-b24d-435f-9425-4e642ad1ab49', '8ef857d3-fd72-4595-8339-a4f25e83dab7', 'Areon Car Perfume Gold - Design inspirador aliado a perfumes marcantes.', 'Areon Car Perfume Gold - Design inspirador aliado a perfumes marcantes para um ambiente refrescante. Aroma: Exclusivo de fundo almiscarado e notas refrescantes. Família olfativa: Spicy. Notas de saída: cítrico e amadeirado. Notas de coração: lavanda, anis, eucalipto, rosa. Notas de fundo: almíscar, âmbar, patchouli. Conteúdo: 01 odorizador de ambiente spray (50ml) e um difusor de celulose.', '{"Embalagem": "01 odorizador spray (50ml) e difusor de celulose", "Fragrância": "Exclusivo de fundo almiscarado e notas refrescantes", "Notas de saída": "cítrico e amadeirado", "Família olfativa": "Spicy", "Notas de coração": "lavanda, anis, eucalipto, rosa"}'::jsonb, '1- Retire o conteúdo da embalagem. 2- Pendure a celulose em seu veiculo, ou onde desejar, e retire a tampa do frasco. 3- Pulverizar duas ou três vezes dentro do carro ou sobre o cartão de celulose.', NULL, 'https://images.tcdn.com.br/img/img_prod/1152560/areon_car_perfume_gold_50ml_817_1_2850c32802663e40b584baee150a6579.jpg', '{}'::text[], 4.5, 1, false, false, '{}'::text[], '2026-07-12T00:07:20.369681+00:00', 'published', NULL, '2026-07-12T01:40:33.911531+00:00', NULL, NULL);
