INSERT INTO public.products (id, name, slug, brand_id, category_id, short_description, description, specifications, usability, tips, image_url, gallery_images, rating, review_count, is_featured, is_new, tags, created_at, status, publish_at, published_at, parent_product_id, variant_label) VALUES ('5642642c-2b40-4a9a-b836-b330a51b4b08', 'Black Magic Tratamento Super Preto para Pneus Soft99 150ml', 'black-magic-soft99-150ml', 'e992f177-70fb-4f9e-8188-455de352d018', 'f1341dff-415a-4e17-8262-5549273d6b1d', 'Black Magic Soft 99 tratamento super preto para pneus. Brilho seco e natural, longa durabilidade.', 'Black Magic é um tratamento para pneus que traz um novo conceito do conhecido "pretinho". Diferentemente de outros produtos similares, Black Magic tem durabilidade de até 60 dias. Seu brilho é acetinado. Não deixa aspecto melado nem grudento. Após aplicação, cria uma camada repelente a água e a sujeira. Conteúdo: 150ml. Rendimento: até 40 pneus. Durabilidade: até 2 meses.', '{"Peso": "241 g", "Acompanha": "Luva Plástica", "Conteúdo": "150ml", "Rendimento": "até 40 pneus", "Durabilidade": "até 2 meses"}'::jsonb, '1- Lavar e secar bem os pneus antes da aplicação. 2- Agite bem o produto e pressione levemente a esponja aplicadora sobre o pneu. 3- Aplique de maneira uniforme uma fina camada. 4- Deixe secar de 10 a 20 minutos. 5- Feche a tampa e guarde com a esponja virada para cima.', 'Dica: Para um acabamento mais refinado, recomendamos a utilização da Esponja Tire Wax Soft99.', 'https://images.tcdn.com.br/img/img_prod/1152560/tratamento_super_preto_para_pneus_black_magic_soft99_150ml_651_1_5cb0dc16e917457f564d0a77dea5b364.jpg', '{}'::text[], 5, 1, false, false, '{}'::text[], '2026-07-12T00:06:58.200838+00:00', 'published', NULL, '2026-07-12T01:40:33.911531+00:00', NULL, NULL);
INSERT INTO public.products (id, name, slug, brand_id, category_id, short_description, description, specifications, usability, tips, image_url, gallery_images, rating, review_count, is_featured, is_new, tags, created_at, status, publish_at, published_at, parent_product_id, variant_label) VALUES ('e4b8f511-c756-4ebd-b3ac-c3d6acd404ff', 'Blend Paste Wax Cera em Pasta Vonixx 100g', 'blend-paste-wax-vonixx-100g', '2521bc20-0c66-4bea-91fa-83cef52db28b', 'f1341dff-415a-4e17-8262-5549273d6b1d', 'Cera em pasta com carnaúba e sílica. Proteção de até 7 meses.', 'Sabemos que a cera de carnaúba é conhecida pelo brilho quente que proporciona à pintura. Com a evolução do mercado há crescente tendência para os produtos à base de sílica. A Vonixx desenvolveu a BLEND CARNAÚBA SÍLICA PASTE WAX, unindo cera de carnaúba tipo 1 brasileira e sílica. O filme de proteção repele fortemente água, com proteção de até 7 meses.', '{"Peso": "100g", "Tipo": "Cera em Pasta", "Marca": "Vonixx", "Composição": "Carnaúba + SiO2"}'::jsonb, '1. Lavar bem o veículo e certificar-se que a pintura esteja livre de contaminantes. 2. Aplicar com aplicador de espuma em movimentos uniformes. 3. Aguardar entre 5 e 10 minutos. 4. Remover com toalha de microfibra. 5. Uma segunda camada proporcionará brilho e proteção maior.', NULL, 'https://images.tcdn.com.br/img/img_prod/1152560/blend_paste_wax_cera_em_pasta_vonixx_100g_1011_1_ea81d48538cdf6ecd263a309d786e11d.jpg', '{}'::text[], 5, 3, true, true, '{}'::text[], '2026-07-12T00:05:35.180408+00:00', 'published', NULL, '2026-07-12T01:40:33.911531+00:00', NULL, NULL);
INSERT INTO public.products (id, name, slug, brand_id, category_id, short_description, description, specifications, usability, tips, image_url, gallery_images, rating, review_count, is_featured, is_new, tags, created_at, status, publish_at, published_at, parent_product_id, variant_label) VALUES ('f5048bd2-acc6-4084-9225-ff20f2f0f8f8', 'Carnaúba Paste Wax Evox 200g', 'carnauba-paste-wax-evox-200g', 'd78b1eae-ba8a-4bc9-b51a-9e17174a6cda', 'f1341dff-415a-4e17-8262-5549273d6b1d', 'Cera em pasta com carnaúba natural tipo 1. Brilho quente e proteção por até 4 meses.', 'Carnaúba Paste Wax Evox (200g) - Cera de alto padrão, de fácil aplicação e isenta de abrasivos. Composição à base de cera de carnaúba 100% natural tipo 1, promove brilho quente, toque aveludado e proteção por até 4 meses.', '{"Peso": "200g", "Tipo": "Cera em Pasta", "Marca": "Evox", "Composição": "Carnaúba 100% natural tipo 1"}'::jsonb, 'Lavar bem o veículo e certificar-se de que a pintura esteja limpa e seca. Aplicar com aplicador de espuma em movimentos circulares. Aguardar de 3 a 5 minutos e remover com toalha de microfibra.', 'Pronto uso. Duração média: até 4 meses. Rendimento médio: até 60 veículos. Indicado para uso em superfícies com ou sem vitrificação.', 'https://images.tcdn.com.br/img/img_prod/1152560/carnauba_paste_wax_evox_200g_1333_1_78b86fbbc7ea528362873d2385f5ee32.jpg', '{}'::text[], 4, 1, false, false, '{}'::text[], '2026-07-12T00:05:35.180408+00:00', 'published', NULL, '2026-07-12T01:40:33.911531+00:00', NULL, NULL);
INSERT INTO public.products (id, name, slug, brand_id, category_id, short_description, description, specifications, usability, tips, image_url, gallery_images, rating, review_count, is_featured, is_new, tags, created_at, status, publish_at, published_at, parent_product_id, variant_label) VALUES ('9ab206f8-d97f-4a69-a669-d8b8a8436254', 'Cera em Pasta Hard Wax Cadillac 300g', 'cera-hard-wax-cadillac-300g', '89fcb84c-3878-4df6-b40a-091b42980372', 'f1341dff-415a-4e17-8262-5549273d6b1d', 'Cera em pasta com carnaúba branca tipo 1. Proteção por até 6 meses com efeito hidrofóbico.', 'A Cera em Pasta Hard Wax Cadillac é fabricada com carnaúba branca tipo 1, de altíssima qualidade. Realça a profundidade da coloração, com durabilidade de proteção de até 6 meses contra raios UV, chuvas, fuligem e maresia. Possui propriedade hidrofóbica e cera de abelha na formulação.', '{"Conteúdo": "150g", "Itens inclusos": "1 Cera Cadillac Hard Wax 150g e 1 Aplicador de Espuma"}'::jsonb, 'Aplicar sobre pintura devidamente preparada e espelhada, isenta de micro-riscos. Aplicar com aplicador de espuma, aguardar e remover com toalha de microfibra.', 'Conteúdo: 150g. Itens inclusos: 1 Cera Cadillac Hard Wax 150g e 1 Aplicador de Espuma.', 'https://images.tcdn.com.br/img/img_prod/1152560/cera_em_pasta_hard_wax_cadillac_300g_311_1_63ff25448a36648b31da7b29a52c667d.jpg', '{}'::text[], 4.5, 2, false, false, '{}'::text[], '2026-07-12T00:05:35.180408+00:00', 'published', NULL, '2026-07-12T01:40:33.911531+00:00', NULL, NULL);
INSERT INTO public.products (id, name, slug, brand_id, category_id, short_description, description, specifications, usability, tips, image_url, gallery_images, rating, review_count, is_featured, is_new, tags, created_at, status, publish_at, published_at, parent_product_id, variant_label) VALUES ('23c7fa97-2a61-4879-9658-2f309fef53df', 'Cera Fusso Coat Black Soft99 200g', 'cera-fusso-coat-black-soft99-200g', 'e992f177-70fb-4f9e-8188-455de352d018', 'f1341dff-415a-4e17-8262-5549273d6b1d', 'Cera selante sintética com polímeros de flúor, durabilidade de até 12 meses. Ideal para cores escuras.', 'Cera/Selante Fusso Coat Black Soft99 possui polímeros sintéticos de alta resistência à base de flúor que pode durar até 12 meses na lataria. Proporciona ultra repelência de água e sujeira, mantendo a superfície sempre limpa. Protege contra produtos químicos, poluições, chuva ácida, riscos, raios UV e ação do tempo. Efeito ultra brilhante, ideal para carros pretos ou de cores escuras. Textura sólida (pasta dura). Acompanha espuma aplicadora. Rendimento aproximado: 40 carros médios.', '{"Peso": "200g", "Tipo": "Sintética", "Marca": "Soft99", "Origem": "Japão", "Textura": "Pasta Dura", "Rendimento": "~40 carros", "Durabilidade": "Até 12 meses"}'::jsonb, NULL, NULL, 'https://images.tcdn.com.br/img/img_prod/1152560/cera_fusso_coat_black_para_cores_escuras_soft99_200g_867_1_f49c1af8865ce891629e5d24545b1b92.jpg', '{}'::text[], 5, 3, true, false, '{}'::text[], '2026-07-12T00:05:35.180408+00:00', 'published', NULL, '2026-07-12T01:40:33.911531+00:00', NULL, NULL);
INSERT INTO public.products (id, name, slug, brand_id, category_id, short_description, description, specifications, usability, tips, image_url, gallery_images, rating, review_count, is_featured, is_new, tags, created_at, status, publish_at, published_at, parent_product_id, variant_label) VALUES ('862ef68f-4718-48f1-b200-aea50a5f9c74', 'Cera Fusso Coat Light Soft99 200g', 'cera-fusso-coat-light-soft99-200g', 'e992f177-70fb-4f9e-8188-455de352d018', 'f1341dff-415a-4e17-8262-5549273d6b1d', 'Cera e selante sintético com polímeros de flúor para cores claras. Durabilidade de até 12 meses.', 'Cera e Selante Sintético Fusso Coat Light Soft99 possui polímeros sintéticos de alta resistência à base de flúor que pode durar até 12 meses na lataria. Ideal para carros de cores claras. Proporciona ultra repelência de água e sujeira. Protege contra produtos químicos, poluições, chuva ácida, riscos, raios UV e ação do tempo.', '{"Peso": "200g", "Tipo": "Sintética", "Marca": "Soft99", "Origem": "Japão", "Textura": "Pasta Dura", "Durabilidade": "Até 12 meses"}'::jsonb, NULL, NULL, 'https://images.tcdn.com.br/img/img_prod/1152560/cera_fusso_coat_light_para_cores_claras_soft99_200g_869_2_abd36fcaf6d4819d4f3d8c0e8af93260.jpg', '{}'::text[], 5, 2, true, false, '{}'::text[], '2026-07-12T00:05:35.180408+00:00', 'published', NULL, '2026-07-12T01:40:33.911531+00:00', NULL, NULL);
INSERT INTO public.products (id, name, slug, brand_id, category_id, short_description, description, specifications, usability, tips, image_url, gallery_images, rating, review_count, is_featured, is_new, tags, created_at, status, publish_at, published_at, parent_product_id, variant_label) VALUES ('15c303d7-51dd-4b33-81ab-28edce6a5b9c', 'Cera Líquida Autoshine 500ml', 'cera-liquida-autoshine-500ml', 'ea720c10-751e-4e7a-a83c-547e3152d45c', 'f1341dff-415a-4e17-8262-5549273d6b1d', 'Cera líquida à base de resinas especiais para proteger, renovar e restaurar a cor original do veículo.', 'A Cera Líquida Autoshine é um produto à base de resinas especiais desenvolvido para proteger, renovar e restaurar a cor original do veículo. Fácil aplicação e brilho duradouro.', '{"Tipo": "Cera Líquida", "Marca": "Autoshine", "Volume": "500ml"}'::jsonb, NULL, NULL, 'https://images.tcdn.com.br/img/img_prod/1152560/cera_liquida_autoshine_500ml_307_1_1d5da93c435f777cdd38a6c7030244db.jpg', '{}'::text[], 4, 1, false, false, '{}'::text[], '2026-07-12T00:05:35.180408+00:00', 'published', NULL, '2026-07-12T01:40:53.21361+00:00', NULL, NULL);
