INSERT INTO public.products (id, name, slug, brand_id, category_id, short_description, description, specifications, usability, tips, image_url, gallery_images, rating, review_count, is_featured, is_new, tags, created_at, status, publish_at, published_at, parent_product_id, variant_label) VALUES ('b31d52ff-cfe1-43cc-9173-bab2d3ec6625', 'Citrus Shampoo Automotivo Evox 500ml', 'citrus-shampoo-evox-500ml', 'd78b1eae-ba8a-4bc9-b51a-9e17174a6cda', '330f3e55-c35d-411b-afff-3d2184e0f3b9', 'Shampoo de alto rendimento com pH neutro que limpa, mantém e renova o brilho sem remover ceras ou selantes.', 'CITRUS é um produto de alto rendimento com pH neutro que limpa, mantém e renova o brilho da pintura sem remover ceras ou selantes da superfície. Diluição de até 1:400, oferece excelente rendimento e lubrificação para lavagem segura.', '{"pH": "Neutro", "Marca": "Evox", "Volume": "500ml", "Diluição": "Até 1:400"}'::jsonb, NULL, NULL, 'https://images.tcdn.com.br/img/img_prod/1152560/citrus_shampoo_automotivo_evox_500ml_diluicao_ate_1_400_1355_1_7bbb5ab422662177f768c4cb5799eaa8.jpg', '{}'::text[], 4, 2, false, false, '{}'::text[], '2026-07-12T00:05:02.697657+00:00', 'published', NULL, '2026-07-12T01:48:35.23035+00:00', NULL, NULL);
INSERT INTO public.products (id, name, slug, brand_id, category_id, short_description, description, specifications, usability, tips, image_url, gallery_images, rating, review_count, is_featured, is_new, tags, created_at, status, publish_at, published_at, parent_product_id, variant_label) VALUES ('31524f93-157d-462a-a06b-393e7db19da0', 'CMX Ceramic Wash & Coat Shampoo com Cera Mothers 1,4L', 'cmx-ceramic-wash-coat-mothers-14l', '9d92839d-dd51-4e10-9ee8-8e298075970d', '330f3e55-c35d-411b-afff-3d2184e0f3b9', 'Shampoo com cera cerâmica que lubrifica, dissolve sujeira e neutraliza minerais causadores de manchas.', 'Esta fórmula de alta eficiência lubrifica e dissolve a sujeira. Suspende os contaminantes opacos, enquanto neutraliza os minerais que causam manchas de água. CMX Ceramic Wash & Coat é um shampoo com tecnologia cerâmica que protege e mantém o brilho da pintura.', '{"Tipo": "Shampoo com Cera", "Marca": "Mothers", "Volume": "1,4 Litros", "Tecnologia": "Cerâmica"}'::jsonb, NULL, NULL, 'https://images.tcdn.com.br/img/img_prod/1152560/cmx_ceramic_wash_coat_shampoo_com_cera_mothers_1_4_l_1455_1_c36288fb6d6dff48169e6523de8c5686.jpg', '{}'::text[], 4.5, 2, false, true, '{}'::text[], '2026-07-12T00:05:02.697657+00:00', 'published', NULL, '2026-07-12T01:48:35.23035+00:00', NULL, NULL);
INSERT INTO public.products (id, name, slug, brand_id, category_id, short_description, description, specifications, usability, tips, image_url, gallery_images, rating, review_count, is_featured, is_new, tags, created_at, status, publish_at, published_at, parent_product_id, variant_label) VALUES ('2fe6e005-a674-4344-a4f8-34564516caed', 'Composto Polidor Lincoln 500g', 'composto-polidor-lincoln-500g', '791f9478-d15a-4863-966b-90777fa6bfb0', 'f13b7270-b3c6-449b-b1d0-78394cafbd51', 'Composto polidor multiuso à base de água, sem cera e sem silicone. Médio poder de corte e ótimo acabamento.', 'Produto à base de água, desenvolvido sem cera e sem silicone. O COMPOSTO POLIDOR é um MULTIUSO no Polimento Técnico, eficaz na remoção de marcas de lixamento leve e pequenos arranhões sobre tinta ou verniz. Possui médio poder de corte, ótimo acabamento e alto rendimento. Não mancha borrachas ou partes plásticas, não gruda na superfície durante o polimento. Os resíduos são removidos facilmente com água ou pano úmido.', '{"Base": "À base de água", "Peso": "500g", "Tipo": "Composto Polidor", "Corte": "Médio", "Marca": "Lincoln", "Sem Silicone": "Sim"}'::jsonb, NULL, NULL, 'https://images.tcdn.com.br/img/img_prod/1152560/composto_polidor_lincoln_500g_295_1_ece76e4e4698bbd9351463ab4b24ff66.jpg', '{}'::text[], 4.5, 3, true, false, '{}'::text[], '2026-07-12T00:06:02.620504+00:00', 'published', NULL, '2026-07-12T01:40:53.21361+00:00', NULL, NULL);
