INSERT INTO public.products (id, name, slug, brand_id, category_id, short_description, description, specifications, usability, tips, image_url, gallery_images, rating, review_count, is_featured, is_new, tags, created_at, status, publish_at, published_at, parent_product_id, variant_label) VALUES ('0682376b-8883-45bc-8f08-42940aa36471', 'Glaco 45km/h Cristalizador de Vidros Soft99 75ml', 'glaco-45kmh-soft99-75ml', 'e992f177-70fb-4f9e-8188-455de352d018', '70c01ac7-0184-4d49-9e17-8887cfd4cf7c', 'Cristalizador de vidros que repelir a água. Em deslocamentos acima de 45km/h dispensa o limpador.', 'GLACO é um cristalizador de vidros desenvolvido para repelir a água que se acumula sobre para-brisas automotivos em dias chuvosos. A tecnologia contida nos produtos da linha Glaco garantem a formação de uma película protetora nos vidros que impede que as gotas de chuva "grudem" na superfície. Em deslocamentos acima de 45km/h o efeito do Glaco se mostra eficiente, proporcionando ótima visibilidade. Protege o vidro contra agentes externos como fezes de pássaros, poluição e óleos. Rendimento: até 18 para-brisas. Durabilidade: até 2 meses.', '{"Tipo": "Cristalizador de Vidros", "Marca": "Soft99", "Origem": "Japão", "Volume": "75ml", "Rendimento": "Até 18 para-brisas", "Repelência": "Nível 9", "Durabilidade": "Até 2 meses"}'::jsonb, NULL, NULL, 'https://images.tcdn.com.br/img/img_prod/1152560/glaco_45km_h_cristalizador_de_vidros_repelente_de_chuva_soft99_04132_75ml_211_1_c60e62047d943b1eb1798e4e6b2c757f.jpg', '{}'::text[], 5, 4, true, false, '{}'::text[], '2026-07-12T00:06:58.200838+00:00', 'published', NULL, '2026-07-12T01:40:53.21361+00:00', NULL, NULL);
INSERT INTO public.products (id, name, slug, brand_id, category_id, short_description, description, specifications, usability, tips, image_url, gallery_images, rating, review_count, is_featured, is_new, tags, created_at, status, publish_at, published_at, parent_product_id, variant_label) VALUES ('e4165102-b059-4dfc-b728-251b0402b9c9', 'Glaco Big Roll On Repelente de Água Soft99 120ml', 'glaco-big-roll-on-soft99-120ml', 'e992f177-70fb-4f9e-8188-455de352d018', '70c01ac7-0184-4d49-9e17-8887cfd4cf7c', 'Cristalizador de vidros em formato roll-on para aplicação prática. Repelir a água da chuva.', 'BIG GLACO é um cristalizador de vidros desenvolvido para repelir a água que se acumula sobre para-brisas automotivos em dias chuvosos. Formato roll-on para aplicação prática e uniforme. Tecnologia de longa durabilidade.', '{"Tipo": "Cristalizador de Vidros", "Marca": "Soft99", "Origem": "Japão", "Volume": "120ml", "Aplicação": "Roll-on"}'::jsonb, NULL, NULL, 'https://images.tcdn.com.br/img/img_prod/1152560/glaco_big_roll_on_cristalizador_de_vidros_e_repele_1_20260205163952_dc52fcf7e1b7.jpg', '{}'::text[], 5, 2, false, false, '{}'::text[], '2026-07-12T00:06:58.200838+00:00', 'published', NULL, '2026-07-12T01:40:53.21361+00:00', NULL, NULL);
