INSERT INTO public.products (id, name, slug, brand_id, category_id, short_description, description, specifications, usability, tips, image_url, gallery_images, rating, review_count, is_featured, is_new, tags, created_at, status, publish_at, published_at, parent_product_id, variant_label) VALUES ('981404e5-30e7-484e-befe-3b5d25016972', 'V-FLOC Lava Auto Super Concentrado Vonixx 1,5L', 'v-floc-lava-auto-vonixx-15l', '2521bc20-0c66-4bea-91fa-83cef52db28b', '330f3e55-c35d-411b-afff-3d2184e0f3b9', 'Lava autos de alta performance, pH neutro, super concentrado com diluição 1:400.', 'V-FLOC é um lava autos de alta performance e de pH neutro. Sua fórmula contém agentes condicionadores e tensoativos especiais que proporcionam uma lavagem suave e eficiente. V-FLOC tem alto grau de lubrificação, promovendo redução significativa do coeficiente de atrito, proporcionando um melhor deslize da luva de microfibra e reduzindo de forma efetiva as chances de microrriscos na pintura. Também promove brilho e aspecto de renovação da pintura. Diluição: 1:20 para Snow Foam, 1:400 para lavagem comum com balde.', '{"pH": "Neutro", "Marca": "Vonixx", "Volume": "1,5 Litros", "Diluição": "1:400 (lavagem) / 1:20 (snow foam)", "Rendimento": "Até 600 litros de solução"}'::jsonb, NULL, NULL, 'https://images.tcdn.com.br/img/img_prod/1152560/v_floc_lava_auto_super_concentrado_diluicao_1_400_vonixx_500ml_1501_1_c0b4dbb016b38f702762f81d23c53b48.jpg', '{}'::text[], 5, 4, true, false, '{}'::text[], '2026-07-12T00:05:02.697657+00:00', 'published', NULL, '2026-07-12T01:41:28.083661+00:00', NULL, NULL);
INSERT INTO public.products (id, name, slug, brand_id, category_id, short_description, description, specifications, usability, tips, image_url, gallery_images, rating, review_count, is_featured, is_new, tags, created_at, status, publish_at, published_at, parent_product_id, variant_label) VALUES ('0707ffcf-4c43-49f4-89e4-55aea6efe919', 'V-POLISH Polidor de Refino e Lustro Vonixx 500ml', 'v-polish-refino-lustro-vonixx-500ml', '2521bc20-0c66-4bea-91fa-83cef52db28b', 'f13b7270-b3c6-449b-b1d0-78394cafbd51', 'Composto polidor de refino com tecnologia VHP (Voxer Hybrid Polish) para excelente acabamento.', 'V-POLISH é um composto polidor de refino desenvolvido com tecnologia VHP (Voxer Hybrid Polish), que proporciona excelente acabamento para todos os tipos de verniz. Promove brilho intenso e remoção eficiente de defeitos leves a moderados.', '{"Tipo": "Composto Polidor", "Etapa": "Refino/Lustro", "Marca": "Vonixx", "Volume": "500ml", "Tecnologia": "VHP"}'::jsonb, NULL, NULL, 'https://images.tcdn.com.br/img/img_prod/1152560/v_polish_polidor_de_refino_e_lustro_etapa_2_sistema_vhp_vonixx_500ml_1867_1_43b7d079e4b747690b390a75b0574448.jpg', '{}'::text[], 4.5, 1, false, true, '{}'::text[], '2026-07-12T00:06:02.620504+00:00', 'published', NULL, '2026-07-12T01:41:28.083661+00:00', NULL, NULL);
INSERT INTO public.products (id, name, slug, brand_id, category_id, short_description, description, specifications, usability, tips, image_url, gallery_images, rating, review_count, is_featured, is_new, tags, created_at, status, publish_at, published_at, parent_product_id, variant_label) VALUES ('c2364c8c-3bd0-4fba-ae05-39ba82961cab', 'V80 Selante Sintético Vonixx 500ml', 'v80-selante-sintetico-vonixx-500ml', '2521bc20-0c66-4bea-91fa-83cef52db28b', 'f1341dff-415a-4e17-8262-5549273d6b1d', 'Selante sintético com proteção avançada e propriedades hidrofóbicas. Fácil aplicação e remoção.', 'O V80 é um selante sintético desenvolvido para oferecer proteção avançada e propriedades hidrofóbicas à pintura do veículo. Fácil aplicação e remoção, promove brilho intenso e duradouro. Ideal para manutenção de superfícies já protegidas ou como camada base.', '{"Tipo": "Selante Sintético", "Marca": "Vonixx", "Volume": "500ml"}'::jsonb, NULL, NULL, 'https://images.tcdn.com.br/img/img_prod/1152560/v80_selante_sinttico_vonixx_240ml_1_20251209154609_309c864c062c.jpg', '{}'::text[], 4.5, 2, false, false, '{}'::text[], '2026-07-12T00:05:35.180408+00:00', 'published', NULL, '2026-07-12T01:19:04.090023+00:00', NULL, '500ml');
