INSERT INTO public.search_documents (id, entity_type, entity_id, title, subtitle, short_description, search_text, keywords, slug, status, publish_at, image_url, rating, review_count, is_new, updated_at) VALUES ('093022c7-ad5f-428d-9e27-fa30f757bea7', 'product', '29d75a27-24c7-46fc-b9d6-d39ac9b48ee0', 'ALUMINA CUTMAX 1200 Composto Polidor Corte Pesado EasyTech 500ml', 'EasyTech', 'Composto polidor de corte pesado. Remoção rápida de riscos e nivelamento de texturas.', 'Composto polidor de corte pesado. Remoção rápida de riscos e nivelamento de texturas. O composto polidor de corte Alumina Cutmax é revolucionário, um verdadeiro produto One Step. Tremendo poder de corte e acabamento impecável. A capacidade de remoção rápida de riscos e nivelamento de texturas impressiona. É o primeiro composto de corte produzido para qualquer tipo de verniz, dos mais macios aos mais duros e complexos. Usa o exclusivo sistema EASY SIA de abrasivos inteligentes, formados em 5 tipos de grão. Sem geração de pó. Alternativa rápida e de extrema qualidade para processos de polimento. EasyTech Polimento e Vitrificadores 1. Alumina Cutmax pode ser usado em máquinas rotativas e roto orbitais. 2. Coloque produto na boina de polimento e espalhe com a máquina desligada. 3. Com o produto espalhado na peça, inicie o processo de polimento. 4. Na fase inicial trabalhe com uma leve pressão e mais velocidade. 5. Diminua a pressão e a velocidade a medida que os abrasivos forem quebrando. 6. Remova da peça com um pano de microfibras e use IPA ETS para inspeção final.', '{}'::text[], 'alumina-cutmax-1200-easytech-500ml', 'published', NULL, 'https://images.tcdn.com.br/img/img_prod/1152560/alumina_cutmax_1200_composto_polidor_de_corte_pesado_easytech_500ml_1951_1_166a2c6fc1095e45ac456d309fe7530a.jpg', 4.5, 2, true, '2026-07-19T17:02:32.45277+00:00');
INSERT INTO public.search_documents (id, entity_type, entity_id, title, subtitle, short_description, search_text, keywords, slug, status, publish_at, image_url, rating, review_count, is_new, updated_at) VALUES ('68433798-a5cb-41c5-80ac-837ae1ff2353', 'product', '6062980f-c286-462d-8dbb-5681fb8ee3ca', 'ALUMINA DETAILING 2500 Composto Polidor de Refino EasyTech 500ml', 'EasyTech', 'Composto polidor de refino. Nivelamento de texturas e preparo para lustro.', 'Composto polidor de refino. Nivelamento de texturas e preparo para lustro. Sabemos que a cera de carnaúba é conhecida pelo brilho quente que proporciona à pintura. Com a evolução do mercado há crescente tendência para os produtos à base de polímeros e resinas sintéticas. A Easytech desenvolveu a Alumina Detailing, um composto de refino que alia o melhor dos dois mundos. A capacidade de refino e nivelamento de texturas impressiona, é o primeiro composto de refino produzido para qualquer tipo de verniz. EasyTech Polimento e Vitrificadores Alumina Detailing pode ser usado em máquinas rotativas e roto orbitais. Coloque produto na boina de polimento e espalhe com a máquina desligada. Com o produto espalhado na peça, inicie o processo de polimento.', '{}'::text[], 'alumina-detailing-2500-easytech-500ml', 'published', NULL, 'https://images.tcdn.com.br/img/img_prod/1152560/alumina_detailing_2500_composto_polidor_de_refino_easytech_500ml_1947_1_3248b76d3eb704a5b242a661a11fa72f.jpg', 4, 1, true, '2026-07-19T17:02:32.45277+00:00');
INSERT INTO public.search_documents (id, entity_type, entity_id, title, subtitle, short_description, search_text, keywords, slug, status, publish_at, image_url, rating, review_count, is_new, updated_at) VALUES ('b8477665-8993-47b9-858c-460eeb3ba56a', 'product', '0e6cd462-5bae-4cd1-8eda-2a389991cc70', 'ALUMINA PERFECT GLOSS 3500 Composto Polidor de Lustro EasyTech 500ml', 'EasyTech', 'Composto polidor de lustro. Acabamento impecável e brilho intenso.', 'Composto polidor de lustro. Acabamento impecável e brilho intenso. A capacidade de refino e nivelamento de texturas impressiona. É o primeiro composto de lustro produzido para qualquer tipo de verniz. Indicado para finalização de processos de polimento. EasyTech Polimento e Vitrificadores Alumina Perfect Gloss pode ser usado em máquinas rotativas e roto orbitais. Coloque produto na boina de polimento e espalhe com a máquina desligada. Com o produto espalhado na peça, inicie o processo de polimento.', '{}'::text[], 'alumina-perfect-gloss-3500-easytech-500ml', 'published', NULL, 'https://images.tcdn.com.br/img/img_prod/1152560/alumina_perfect_gloss_3500_composto_polidor_de_lustro_easytech_500ml_1943_1_252c82346ee4c9ba147750c0a73875a7.jpg', 4.5, 1, true, '2026-07-19T17:02:32.45277+00:00');
