INSERT INTO public.search_documents (id, entity_type, entity_id, title, subtitle, short_description, search_text, keywords, slug, status, publish_at, image_url, rating, review_count, is_new, updated_at) VALUES ('3c0a6d64-6c15-4f52-9764-10359418a35f', 'product', '5642642c-2b40-4a9a-b836-b330a51b4b08', 'Black Magic Tratamento Super Preto para Pneus Soft99 150ml', 'Soft99', 'Black Magic Soft 99 tratamento super preto para pneus. Brilho seco e natural, longa durabilidade.', 'Black Magic Soft 99 tratamento super preto para pneus. Brilho seco e natural, longa durabilidade. Black Magic é um tratamento para pneus que traz um novo conceito do conhecido "pretinho". Diferentemente de outros produtos similares, Black Magic tem durabilidade de até 60 dias. Seu brilho é acetinado. Não deixa aspecto melado nem grudento. Após aplicação, cria uma camada repelente a água e a sujeira. Conteúdo: 150ml. Rendimento: até 40 pneus. Durabilidade: até 2 meses. Soft99 Ceras e Selantes 1- Lavar e secar bem os pneus antes da aplicação. 2- Agite bem o produto e pressione levemente a esponja aplicadora sobre o pneu. 3- Aplique de maneira uniforme uma fina camada. 4- Deixe secar de 10 a 20 minutos. 5- Feche a tampa e guarde com a esponja virada para cima. Dica: Para um acabamento mais refinado, recomendamos a utilização da Esponja Tire Wax Soft99.', '{}'::text[], 'black-magic-soft99-150ml', 'published', NULL, 'https://images.tcdn.com.br/img/img_prod/1152560/tratamento_super_preto_para_pneus_black_magic_soft99_150ml_651_1_5cb0dc16e917457f564d0a77dea5b364.jpg', 5, 1, false, '2026-07-19T17:02:32.45277+00:00');
INSERT INTO public.search_documents (id, entity_type, entity_id, title, subtitle, short_description, search_text, keywords, slug, status, publish_at, image_url, rating, review_count, is_new, updated_at) VALUES ('f60f69a1-c400-4a38-8596-d11820036a0d', 'product', 'e4b8f511-c756-4ebd-b3ac-c3d6acd404ff', 'Blend Paste Wax Cera em Pasta Vonixx 100g', 'Vonixx', 'Cera em pasta com carnaúba e sílica. Proteção de até 7 meses.', 'Cera em pasta com carnaúba e sílica. Proteção de até 7 meses. Sabemos que a cera de carnaúba é conhecida pelo brilho quente que proporciona à pintura. Com a evolução do mercado há crescente tendência para os produtos à base de sílica. A Vonixx desenvolveu a BLEND CARNAÚBA SÍLICA PASTE WAX, unindo cera de carnaúba tipo 1 brasileira e sílica. O filme de proteção repele fortemente água, com proteção de até 7 meses. Vonixx Ceras e Selantes 1. Lavar bem o veículo e certificar-se que a pintura esteja livre de contaminantes. 2. Aplicar com aplicador de espuma em movimentos uniformes. 3. Aguardar entre 5 e 10 minutos. 4. Remover com toalha de microfibra. 5. Uma segunda camada proporcionará brilho e proteção maior.', '{}'::text[], 'blend-paste-wax-vonixx-100g', 'published', NULL, 'https://images.tcdn.com.br/img/img_prod/1152560/blend_paste_wax_cera_em_pasta_vonixx_100g_1011_1_ea81d48538cdf6ecd263a309d786e11d.jpg', 5, 3, true, '2026-07-19T17:02:32.45277+00:00');
INSERT INTO public.search_documents (id, entity_type, entity_id, title, subtitle, short_description, search_text, keywords, slug, status, publish_at, image_url, rating, review_count, is_new, updated_at) VALUES ('b8a46da3-3add-43c1-8229-aefce3a556d7', 'product', 'f5048bd2-acc6-4084-9225-ff20f2f0f8f8', 'Carnaúba Paste Wax Evox 200g', 'Evox', 'Cera em pasta com carnaúba natural tipo 1. Brilho quente e proteção por até 4 meses.', 'Cera em pasta com carnaúba natural tipo 1. Brilho quente e proteção por até 4 meses. Carnaúba Paste Wax Evox (200g) - Cera de alto padrão, de fácil aplicação e isenta de abrasivos. Composição à base de cera de carnaúba 100% natural tipo 1, promove brilho quente, toque aveludado e proteção por até 4 meses. Evox Ceras e Selantes Lavar bem o veículo e certificar-se de que a pintura esteja limpa e seca. Aplicar com aplicador de espuma em movimentos circulares. Aguardar de 3 a 5 minutos e remover com toalha de microfibra. Pronto uso. Duração média: até 4 meses. Rendimento médio: até 60 veículos. Indicado para uso em superfícies com ou sem vitrificação.', '{}'::text[], 'carnauba-paste-wax-evox-200g', 'published', NULL, 'https://images.tcdn.com.br/img/img_prod/1152560/carnauba_paste_wax_evox_200g_1333_1_78b86fbbc7ea528362873d2385f5ee32.jpg', 4, 1, false, '2026-07-19T17:02:32.45277+00:00');
INSERT INTO public.search_documents (id, entity_type, entity_id, title, subtitle, short_description, search_text, keywords, slug, status, publish_at, image_url, rating, review_count, is_new, updated_at) VALUES ('62ed6ae9-cc85-41ee-aed9-d4fc8d58875e', 'product', '9ab206f8-d97f-4a69-a669-d8b8a8436254', 'Cera em Pasta Hard Wax Cadillac 300g', 'Cadillac', 'Cera em pasta com carnaúba branca tipo 1. Proteção por até 6 meses com efeito hidrofóbico.', 'Cera em pasta com carnaúba branca tipo 1. Proteção por até 6 meses com efeito hidrofóbico. A Cera em Pasta Hard Wax Cadillac é fabricada com carnaúba branca tipo 1, de altíssima qualidade. Realça a profundidade da coloração, com durabilidade de proteção de até 6 meses contra raios UV, chuvas, fuligem e maresia. Possui propriedade hidrofóbica e cera de abelha na formulação. Cadillac Ceras e Selantes Aplicar sobre pintura devidamente preparada e espelhada, isenta de micro-riscos. Aplicar com aplicador de espuma, aguardar e remover com toalha de microfibra. Conteúdo: 150g. Itens inclusos: 1 Cera Cadillac Hard Wax 150g e 1 Aplicador de Espuma.', '{}'::text[], 'cera-hard-wax-cadillac-300g', 'published', NULL, 'https://images.tcdn.com.br/img/img_prod/1152560/cera_em_pasta_hard_wax_cadillac_300g_311_1_63ff25448a36648b31da7b29a52c667d.jpg', 4.5, 2, false, '2026-07-19T17:02:32.45277+00:00');
INSERT INTO public.search_documents (id, entity_type, entity_id, title, subtitle, short_description, search_text, keywords, slug, status, publish_at, image_url, rating, review_count, is_new, updated_at) VALUES ('eb6ec448-4ae4-485c-bcc4-e61b95e07e5b', 'product', '23c7fa97-2a61-4879-9658-2f309fef53df', 'Cera Fusso Coat Black Soft99 200g', 'Soft99', 'Cera selante sintética com polímeros de flúor, durabilidade de até 12 meses. Ideal para cores escuras.', 'Cera selante sintética com polímeros de flúor, durabilidade de até 12 meses. Ideal para cores escuras. Cera/Selante Fusso Coat Black Soft99 possui polímeros sintéticos de alta resistência à base de flúor que pode durar até 12 meses na lataria. Proporciona ultra repelência de água e sujeira, mantendo a superfície sempre limpa. Protege contra produtos químicos, poluições, chuva ácida, riscos, raios UV e ação do tempo. Efeito ultra brilhante, ideal para carros pretos ou de cores escuras. Textura sólida (pasta dura). Acompanha espuma aplicadora. Rendimento aproximado: 40 carros médios. Soft99 Ceras e Selantes', '{}'::text[], 'cera-fusso-coat-black-soft99-200g', 'published', NULL, 'https://images.tcdn.com.br/img/img_prod/1152560/cera_fusso_coat_black_para_cores_escuras_soft99_200g_867_1_f49c1af8865ce891629e5d24545b1b92.jpg', 5, 3, false, '2026-07-19T17:02:32.45277+00:00');
