INSERT INTO public.search_documents (id, entity_type, entity_id, title, subtitle, short_description, search_text, keywords, slug, status, publish_at, image_url, rating, review_count, is_new, updated_at) VALUES ('69f2f2c6-f460-408c-bb92-656b00d99a61', 'product', '31524f93-157d-462a-a06b-393e7db19da0', 'CMX Ceramic Wash & Coat Shampoo com Cera Mothers 1,4L', 'Mothers', 'Shampoo com cera cerâmica que lubrifica, dissolve sujeira e neutraliza minerais causadores de manchas.', 'Shampoo com cera cerâmica que lubrifica, dissolve sujeira e neutraliza minerais causadores de manchas. Esta fórmula de alta eficiência lubrifica e dissolve a sujeira. Suspende os contaminantes opacos, enquanto neutraliza os minerais que causam manchas de água. CMX Ceramic Wash & Coat é um shampoo com tecnologia cerâmica que protege e mantém o brilho da pintura. Mothers Limpeza Externa', '{}'::text[], 'cmx-ceramic-wash-coat-mothers-14l', 'published', NULL, 'https://images.tcdn.com.br/img/img_prod/1152560/cmx_ceramic_wash_coat_shampoo_com_cera_mothers_1_4_l_1455_1_c36288fb6d6dff48169e6523de8c5686.jpg', 4.5, 2, true, '2026-07-20T00:44:19.410732+00:00');
INSERT INTO public.search_documents (id, entity_type, entity_id, title, subtitle, short_description, search_text, keywords, slug, status, publish_at, image_url, rating, review_count, is_new, updated_at) VALUES ('45e1dc51-1a29-413c-8c75-899056fe4906', 'product', '2fe6e005-a674-4344-a4f8-34564516caed', 'Composto Polidor Lincoln 500g', 'Lincoln', 'Composto polidor multiuso à base de água, sem cera e sem silicone. Médio poder de corte e ótimo acabamento.', 'Composto polidor multiuso à base de água, sem cera e sem silicone. Médio poder de corte e ótimo acabamento. Produto à base de água, desenvolvido sem cera e sem silicone. O COMPOSTO POLIDOR é um MULTIUSO no Polimento Técnico, eficaz na remoção de marcas de lixamento leve e pequenos arranhões sobre tinta ou verniz. Possui médio poder de corte, ótimo acabamento e alto rendimento. Não mancha borrachas ou partes plásticas, não gruda na superfície durante o polimento. Os resíduos são removidos facilmente com água ou pano úmido. Lincoln Polimento e Vitrificadores', '{}'::text[], 'composto-polidor-lincoln-500g', 'published', NULL, 'https://images.tcdn.com.br/img/img_prod/1152560/composto_polidor_lincoln_500g_295_1_ece76e4e4698bbd9351463ab4b24ff66.jpg', 4.5, 3, false, '2026-07-19T17:02:32.45277+00:00');
