INSERT INTO public.search_documents (id, entity_type, entity_id, title, subtitle, short_description, search_text, keywords, slug, status, publish_at, image_url, rating, review_count, is_new, updated_at) VALUES ('9c75410a-68d7-4446-8768-bc26e52afa12', 'product', '0682376b-8883-45bc-8f08-42940aa36471', 'Glaco 45km/h Cristalizador de Vidros Soft99 75ml', 'Soft99', 'Cristalizador de vidros que repelir a água. Em deslocamentos acima de 45km/h dispensa o limpador.', 'Cristalizador de vidros que repelir a água. Em deslocamentos acima de 45km/h dispensa o limpador. GLACO é um cristalizador de vidros desenvolvido para repelir a água que se acumula sobre para-brisas automotivos em dias chuvosos. A tecnologia contida nos produtos da linha Glaco garantem a formação de uma película protetora nos vidros que impede que as gotas de chuva "grudem" na superfície. Em deslocamentos acima de 45km/h o efeito do Glaco se mostra eficiente, proporcionando ótima visibilidade. Protege o vidro contra agentes externos como fezes de pássaros, poluição e óleos. Rendimento: até 18 para-brisas. Durabilidade: até 2 meses. Soft99 Limpeza de Vidros', '{}'::text[], 'glaco-45kmh-soft99-75ml', 'published', NULL, 'https://images.tcdn.com.br/img/img_prod/1152560/glaco_45km_h_cristalizador_de_vidros_repelente_de_chuva_soft99_04132_75ml_211_1_c60e62047d943b1eb1798e4e6b2c757f.jpg', 5, 4, false, '2026-07-19T17:02:32.45277+00:00');
