INSERT INTO public.search_documents (id, entity_type, entity_id, title, subtitle, short_description, search_text, keywords, slug, status, publish_at, image_url, rating, review_count, is_new, updated_at) VALUES ('e5577fef-5b23-487b-9604-1bf3152855cb', 'product', '981404e5-30e7-484e-befe-3b5d25016972', 'V-FLOC Lava Auto Super Concentrado Vonixx 1,5L', 'Vonixx', 'Lava autos de alta performance, pH neutro, super concentrado com diluição 1:400.', 'Lava autos de alta performance, pH neutro, super concentrado com diluição 1:400. V-FLOC é um lava autos de alta performance e de pH neutro. Sua fórmula contém agentes condicionadores e tensoativos especiais que proporcionam uma lavagem suave e eficiente. V-FLOC tem alto grau de lubrificação, promovendo redução significativa do coeficiente de atrito, proporcionando um melhor deslize da luva de microfibra e reduzindo de forma efetiva as chances de microrriscos na pintura. Também promove brilho e aspecto de renovação da pintura. Diluição: 1:20 para Snow Foam, 1:400 para lavagem comum com balde. Vonixx Limpeza Externa', '{}'::text[], 'v-floc-lava-auto-vonixx-15l', 'published', NULL, 'https://images.tcdn.com.br/img/img_prod/1152560/v_floc_lava_auto_super_concentrado_diluicao_1_400_vonixx_500ml_1501_1_c0b4dbb016b38f702762f81d23c53b48.jpg', 5, 4, false, '2026-07-20T00:44:19.410732+00:00');
